// ── RSG Morning Briefing Config — NO AI CREDITS ──
const now = new Date();
const today = now.toISOString().split('T')[0];

const addDays = (d, n) => {
  const dt = new Date(d);
  dt.setDate(dt.getDate() + n);
  return dt.toISOString().split('T')[0];
};

const dayName  = now.toLocaleDateString('en-US', { weekday: 'long' });
const dateLabel = now.toLocaleDateString('en-US', { month: 'long', day: 'numeric', year: 'numeric' });

return [{
  json: {
    // ── Slack Channel IDs ──
    CH_SERVICE:  'C09MA3A7V1B',
    CH_RENEWALS: 'C09R2CG2KS6',
    CH_DEALS:    'C0AFYMES6DU',
    CH_NEWBIZ:   'C0AKFU21ZB9',
    LAMAR_DM:    'U09MM0MGGMP',

    // ── Notion DB IDs ──
    TASKS_DB:    '8a0a8dc4-184f-4afd-8e74-346a4c39c634',
    RENEWALS_DB: 'b8503872-a86e-4269-94ef-73f96a373497',
    NEWBIZ_DB:   '64e5dc39-8883-4f05-973a-3d5f87959b8e',

    // ── Date helpers ──
    today,
    dayName,
    dateLabel,
    in7days:  addDays(today, 7),
    in14days: addDays(today, 14),
    in30days: addDays(today, 30),
    in60days: addDays(today, 60)
  }
}];

