// ── #service-channel: Tasks + Claims ──
const cfg   = $('⚙️ Config').first().json;
const today = cfg.today;

let tasks  = [];
let claims = [];
try { tasks  = $('📋 Fetch Notion Tasks').first().json.results || []; } catch(e) {}
try {
  const raw = $('⚠️ Fetch NowCerts Claims').first().json;
  claims = Array.isArray(raw) ? raw : (raw.claims || raw.data || []);
} catch(e) {}

// Service keyword filter
const SVC = ['renewal','claim','endorsement','certificate','audit','policy','coverage','carrier','underwriting','service','client request','coi','inspection'];
const isSvc = n => SVC.some(k => (n||'').toLowerCase().includes(k));

const now = new Date(today);
const week = new Date(today); week.setDate(week.getDate() + 5);

const overdue = [], dueToday = [], dueWeek = [], later = [];

tasks.forEach(r => {
  const p = r.properties || {};
  const name = p['Task Name']?.title?.[0]?.plain_text || p['Name']?.title?.[0]?.plain_text || 'Unnamed';
  const due  = p['Due Date']?.date?.start || null;
  const who  = p['Assigned To']?.select?.name || p['Assignee']?.people?.[0]?.name || null;
  const url  = r.url || null;
  const item = { name, due, who, url };
  if (!due) { later.push(item); return; }
  const d = new Date(due);
  if (d < now)       overdue.push(item);
  else if (due === today) dueToday.push(item);
  else if (d <= week) dueWeek.push(item);
  else               later.push(item);
});

const fmtT = (t, showDate=true) => {
  let l = `• *${t.name}*`;
  if (t.who)            l += ` | 👤 ${t.who}`;
  if (showDate && t.due) l += ` | 📅 ${t.due}`;
  if (t.url)            l += `\n  🔗 <${t.url}|View>`;
  return l;
};

const fmtClaims = () => {
  if (!claims.length) return '_No open claims_';
  const lines = claims.slice(0,10).map(c => {
    const opened = c.date_of_loss || c.dateOfLoss || c.opened_date || null;
    let days = null;
    if (opened) days = Math.floor((now - new Date(opened)) / 86400000);
    const flag = days && days > 30 ? '🚩' : '•';
    return `${flag} *${c.insured_name||c.insuredName||'Unknown'}* — ${c.line_of_business||c.lob||'—'} — ${c.claim_number||c.claimNumber||'—'}${days!==null?' — '+days+'d open':''} — ${c.status||'—'}`;
  });
  const flagged = claims.filter(c => {
    const o = c.date_of_loss || c.dateOfLoss || c.opened_date;
    return o && Math.floor((now - new Date(o)) / 86400000) > 30;
  }).length;
  return lines.join('\n') + (flagged ? `\n🚨 ${flagged} claim${flagged>1?'s':''} open 30+ days — needs follow-up` : '');
};

let msg = `🛠️ *Service Tasks & Claims — ${cfg.dayName}, ${cfg.dateLabel}*\n`;
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

if (overdue.length) {
  msg += `🔥 *SERVICE PRIORITY*\n  ${overdue[0].name}${overdue[0].due?' (due '+overdue[0].due+')':''} — overdue, handle first\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
}

msg += `⚠️ *OPEN CLAIMS (${claims.length})*\n${fmtClaims()}\n\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n`;
msg += `📋 *SERVICE TASKS*\n`;
if (overdue.length)   { msg += `🔴 Overdue (${overdue.length}):\n`;  overdue.forEach(t  => { msg += `  ${fmtT(t)}\n`; }); }
if (dueToday.length)  { msg += `🟡 Due Today (${dueToday.length}):\n`; dueToday.forEach(t => { msg += `  ${fmtT(t,false)}\n`; }); }
if (dueWeek.length)   { msg += `🟢 This Week (${dueWeek.length}):\n`; dueWeek.forEach(t  => { msg += `  ${fmtT(t)}\n`; }); }
if (!overdue.length && !dueToday.length && !dueWeek.length) msg += '_Clear — no service tasks due this week_ ✅\n';

msg += `\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n`;
msg += `📊 *SNAPSHOT:* ${claims.length} open claims | ${overdue.length+dueToday.length+dueWeek.length} tasks (${overdue.length} overdue)`;

return [{ json: { channel: cfg.CH_SERVICE, message: msg } }];

// ── #renewals: NowCerts renewals ──
const cfg   = $('⚙️ Config').first().json;
const today = cfg.today;

let renewals = [];
try {
  const raw = $('🔄 Fetch NowCerts Renewals').first().json;
  renewals = Array.isArray(raw) ? raw : (raw.renewals || raw.data || []);
} catch(e) {}

const thisWeek=[], nextWeek=[], later=[];
let totalPrem = 0;

rewals = renewals; // alias

rewals.forEach = undefined; // scope safety
const list = renewals;

list.forEach(r => {
  const d = r.renewal_date || r.renewalDate || r.expiration_date || null;
  if (!d) return;
  const days = Math.ceil((new Date(d) - new Date(today)) / 86400000);
  const prem = r.expiring_premium || r.expiringPremium || r.premium || 0;
  totalPrem += prem;
  const item = {
    insured: r.insured_name || r.insuredName || 'Unknown',
    lob:     r.line_of_business || r.lineOfBusiness || r.lob || '—',
    carrier: r.carrier || '—',
    date: d, days, prem
  };
  if (days <= 5)       thisWeek.push(item);
  else if (days <= 10) nextWeek.push(item);
  else                 later.push(item);
});

const fmtR = r => {
  let l = `• *${r.insured}* — ${r.lob} — renews ${r.date}`;
  if (r.prem)        l += ` — $${r.prem.toLocaleString()}`;
  if (r.carrier!=='—') l += ` — ${r.carrier}`;
  if (r.days <= 3)   l += ` ⚡ *${r.days}d*`;
  return l;
};

let msg = `🔄 *Renewals — ${cfg.dayName}, ${cfg.dateLabel}*\n`;
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

if (!list.length) {
  msg += '_No renewals due in the next 30 days. Clear!_ ✅\n';
} else {
  if (thisWeek.length) { msg += `🔴 *This Week (${thisWeek.length}):*\n`; thisWeek.forEach(r => { msg += `  ${fmtR(r)}\n`; }); msg += '\n'; }
  if (nextWeek.length) { msg += `🟠 *Next Week (${nextWeek.length}):*\n`; nextWeek.forEach(r => { msg += `  ${fmtR(r)}\n`; }); msg += '\n'; }
  if (later.length)    { msg += `🟡 *Later This Month (${later.length}):*\n`; later.forEach(r => { msg += `  ${fmtR(r)}\n`; }); msg += '\n'; }
}

msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
msg += `💵 *Total Expiring Premium (30d):* $${totalPrem.toLocaleString()}`;
if (thisWeek.length) msg += `\n🚨 *${thisWeek.length} renewal${thisWeek.length>1?'s':''} due this week — prioritize outreach*`;

return [{ json: { channel: cfg.CH_RENEWALS, message: msg } }];

// ── #deals: Active pipeline deals ──
const cfg = $('⚙️ Config').first().json;
let results = [];
try { results = $('💼 Fetch Notion Deals').first().json.results || []; } catch(e) {}

if (!results.length) {
  return [{ json: { channel: cfg.CH_DEALS, message: `💼 *Active Pipeline — ${cfg.dayName}, ${cfg.dateLabel}*\n\n📭 Pipeline is empty. Time to fill it up! 🎯` } }];
}

let totalVal = 0;
const lines = results.map(r => {
  const p = r.properties || {};
  const client = p['Client / Entity Name']?.title?.[0]?.plain_text || p['Client Name']?.title?.[0]?.plain_text || p['Name']?.title?.[0]?.plain_text || 'Unknown';
  const stage   = p['Stage']?.select?.name || '—';
  const lob     = p['LOB']?.select?.name || p['Line of Business']?.select?.name || '—';
  const premium = p['Est. Annual Premium']?.number || p['Written Premium']?.number || p['Annual Premium']?.number || 0;
  const carrier = p['Carrier']?.select?.name || null;
  const who     = p['Assigned To']?.select?.name || p['Owner']?.people?.[0]?.name || null;
  totalVal += premium;
  let l = `• *${client}*`;
  if (lob !== '—') l += ` (${lob})`;
  l += ` | ${stage}`;
  if (carrier) l += ` | ${carrier}`;
  if (premium) l += ` | 💰 $${premium.toLocaleString()}`;
  if (who)     l += ` | 👤 ${who}`;
  if (r.url)   l += `\n  🔗 <${r.url}|View>`;
  return l;
});

let msg = `💼 *Active Pipeline — ${cfg.dayName}, ${cfg.dateLabel}*\n`;
msg += `_(${results.length} deal${results.length!==1?'s':''})`;
if (totalVal) msg += ` | Est. $${totalVal.toLocaleString()} annual premium`;
msg += '_\n';
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
msg += lines.join('\n\n');

return [{ json: { channel: cfg.CH_DEALS, message: msg } }];

// ── #new-business: Pipeline summary ──
const cfg = $('⚙️ Config').first().json;
let results = [];
try { results = $('💼 Fetch Notion Deals').first().json.results || []; } catch(e) {}

if (!results.length) {
  return [{ json: { channel: cfg.CH_NEWBIZ, message: `📊 *New Business Summary — ${cfg.dayName}, ${cfg.dateLabel}*\n\nPipeline is empty. Time to prospect! 🎯` } }];
}

const stageCounts = {}, lobCounts = {};
let totalPrem = 0, hotCount = 0;

results.forEach(r => {
  const p     = r.properties || {};
  const stage = p['Stage']?.select?.name || 'Unknown';
  const lob   = p['LOB']?.select?.name || p['Line of Business']?.select?.name || 'Unknown';
  const prem  = p['Est. Annual Premium']?.number || p['Written Premium']?.number || p['Annual Premium']?.number || 0;
  stageCounts[stage] = (stageCounts[stage]||0) + 1;
  lobCounts[lob]     = (lobCounts[lob]||0) + 1;
  totalPrem += prem;
  if (/quot|negot|bound/i.test(stage)) hotCount++;
});

const stageLines = Object.entries(stageCounts).sort((a,b)=>b[1]-a[1]).map(([s,c])=>`  • ${s}: ${c}`);
const lobLines   = Object.entries(lobCounts).sort((a,b)=>b[1]-a[1]).map(([l,c])=>`  • ${l}: ${c}`);

let msg = `📊 *New Business Pipeline Summary — ${cfg.dayName}, ${cfg.dateLabel}*\n`;
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';
msg += `*Total Active Deals:* ${results.length}\n`;
if (totalPrem) msg += `*Pipeline Value:* $${totalPrem.toLocaleString()} est. annual premium\n`;
if (hotCount)  msg += `*Quote Stage or Later:* ${hotCount}\n`;
msg += `\n*By Stage:*\n${stageLines.join('\n')}\n\n`;
msg += `*By LOB:*\n${lobLines.join('\n')}`;

return [{ json: { channel: cfg.CH_NEWBIZ, message: msg } }];

// ── Lamar DM: Full snapshot ──
const cfg   = $('⚙️ Config').first().json;
const today = cfg.today;
const now   = new Date(today);

// Collect all data
let tasks    = []; try { tasks    = $('📋 Fetch Notion Tasks').first().json.results || []; } catch(e) {}
let renewals = []; try { const r = $('🔄 Fetch NowCerts Renewals').first().json; renewals = Array.isArray(r)?r:(r.renewals||r.data||[]); } catch(e) {}
let claims   = []; try { const c = $('⚠️ Fetch NowCerts Claims').first().json;    claims   = Array.isArray(c)?c:(c.claims||c.data||[]);   } catch(e) {}
let deals    = []; try { deals    = $('💼 Fetch Notion Deals').first().json.results || [];  } catch(e) {}

// Task stats
let overdueCount=0, dueTodayCount=0, dueWeekCount=0;
const week = new Date(today); week.setDate(week.getDate()+5);
const overdueTasks = [];

tasks.forEach(r => {
  const due  = r.properties?.['Due Date']?.date?.start;
  const name = r.properties?.['Task Name']?.title?.[0]?.plain_text || r.properties?.['Name']?.title?.[0]?.plain_text || 'Task';
  if (!due) return;
  const d = new Date(due);
  if (d < now)        { overdueCount++;   overdueTasks.push({ name, due, daysLate: Math.ceil((now-d)/86400000) }); }
  else if (due===today) dueTodayCount++;
  else if (d <= week)   dueWeekCount++;
});

// Renewal urgency (≤7 days)
const urgentRen = renewals.filter(r => {
  const d = r.renewal_date||r.renewalDate||r.expiration_date;
  return d && Math.ceil((new Date(d)-now)/86400000) <= 7;
});

// Pipeline value
let pipeVal = 0;
deals.forEach(r => { pipeVal += r.properties?.['Est. Annual Premium']?.number||r.properties?.['Written Premium']?.number||0; });

// Flagged claims
const flagged = claims.filter(c => {
  const o = c.date_of_loss||c.dateOfLoss||c.opened_date;
  return o && Math.floor((now-new Date(o))/86400000) > 30;
});

// Compose
let msg = `☀️ *Good morning, Lamar! RSG Snapshot — ${cfg.dayName}, ${cfg.dateLabel}*\n`;
msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n\n';

msg += `📊 *AT A GLANCE*\n`;
msg += `  💼 Active Deals: *${deals.length}*${pipeVal ? ' | Est. *$'+pipeVal.toLocaleString()+'*' : ''}\n`;
msg += `  🔄 Renewals (30d): *${renewals.length}* | Urgent (≤7d): *${urgentRen.length}*\n`;
msg += `  📋 Open Tasks: *${tasks.length}* | Overdue: *${overdueCount}* | Due today: *${dueTodayCount}*\n`;
msg += `  ⚠️ Open Claims: *${claims.length}*${flagged.length ? ' | 🚩 *'+flagged.length+' flagged 30d+*' : ''}\n\n`;

// Urgent callouts
const alerts = [];
if (overdueCount)      alerts.push(`🔴 ${overdueCount} overdue task${overdueCount>1?'s':''}`);
if (urgentRen.length)  alerts.push(`🚨 ${urgentRen.length} renewal${urgentRen.length>1?'s':''} due within 7 days`);
if (flagged.length)    alerts.push(`🚩 ${flagged.length} claim${flagged.length>1?'s':''} open 30+ days`);

if (alerts.length) {
  msg += `⚡ *NEEDS YOUR ATTENTION*\n`;
  alerts.forEach(a => { msg += `  ${a}\n`; });
  msg += '\n';
}

// Overdue preview
if (overdueTasks.length) {
  msg += `🔴 *TOP OVERDUE TASKS*\n`;
  overdueTasks.slice(0,3).forEach(t => { msg += `  • ${t.name} _(${t.daysLate}d late)_\n`; });
  if (overdueTasks.length > 3) msg += `  _...and ${overdueTasks.length-3} more_\n`;
  msg += '\n';
}

// Urgent renewal preview
if (urgentRen.length) {
  msg += `🚨 *URGENT RENEWALS (≤7 days)*\n`;
  urgentRen.slice(0,3).forEach(r => {
    const d = r.renewal_date||r.renewalDate||r.expiration_date;
    const days = d ? Math.ceil((new Date(d)-now)/86400000) : null;
    msg += `  • ${r.insured_name||r.insuredName||'Client'}${days!==null?' _('+ days+'d)_':''}\n`;
  });
  msg += '\n';
}

msg += '━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n';
msg += `_Full details → #service-channel | #renewals | #deals | #new-business_`;

return [{ json: { channel: cfg.LAMAR_DM, message: msg } }];

// Merge all 5 in order: channels first, Lamar DM last
const svc   = $('📝 Format → #service-channel').first().json;
const ren   = $('📝 Format → #renewals').first().json;
const deals = $('📝 Format → #deals').first().json;
const nb    = $('📝 Format → #new-business').first().json;
const lamar = $('📝 Format → Lamar DM').first().json;
return [svc, ren, deals, nb, lamar].map(m => ({ json: m }));
